// Load AI prompts from config
const fs = require('fs');
const promptsPath = '/data/config/ai_prompts.json';
let prompts;

try {
  const promptsData = fs.readFileSync(promptsPath, 'utf8');
  prompts = JSON.parse(promptsData);
} catch (error) {
  // Fallback to default prompts if file doesn't exist
  prompts = {
    "product": {
      "systemPrompt": "You are a product data extraction expert. Extract structured product information from HTML.",
      "userPrompt": "Extract the following information from this product page HTML:

1. SKU (product code/identifier)
2. Product name
3. All image URLs (full resolution preferred)
4. All video URLs
5. Marketing copy/description
6. Any additional metadata (price, dimensions, materials, etc.)

Return ONLY valid JSON in this exact format:
{
  "sku": "string",
  "name": "string",
  "images": ["url1", "url2"],
  "videos": ["url1", "url2"],
  "description": "string",
  "metadata": {}
}

HTML:
"
    },
    "catalog": {
      "systemPrompt": "You are a product catalog extraction expert. Extract multiple products from catalog pages.",
      "userPrompt": "Extract all products from this catalog page HTML. For each product, extract:

1. SKU
2. Product name
3. Image URLs
4. Product page URL (if available)

Return ONLY valid JSON array in this format:
[
  {
    "sku": "string",
    "name": "string",
    "images": ["url"],
    "productUrl": "url"
  }
]

HTML:
"
    },
    "paginated": {
      "systemPrompt": "You are a pagination detection expert. Identify pagination links in HTML.",
      "userPrompt": "Find all pagination links (next page, page numbers) in this HTML. Return ONLY valid JSON:
{
  "nextPageUrl": "url or null",
  "allPageUrls": ["url1", "url2"]
}

HTML:
"
    }
  };
}

const pageType = $input.item.json.pageType || 'product';
const prompt = prompts[pageType] || prompts.product;

return {
  systemPrompt: prompt.systemPrompt,
  userPrompt: prompt.userPrompt,
  html: $input.item.json.html,
  url: $input.item.json.url,
  pageType: pageType
};

// Parse Gemini response and extract JSON
const response = $input.item.json;

try {
  // Extract text from Gemini response structure
  const text = response.candidates[0].content.parts[0].text;

  // Parse the JSON response
  let extractedData;
  try {
    extractedData = JSON.parse(text);
  } catch (parseError) {
    // Try to extract JSON from markdown code blocks
    const jsonMatch = text.match(/```json\s*([\s\S]*?)\s*```/);
    if (jsonMatch) {
      extractedData = JSON.parse(jsonMatch[1]);
    } else {
      throw new Error('Could not parse JSON from Gemini response');
    }
  }

  // Validate required fields based on page type
  const pageType = $('Load AI Prompts').item.json.pageType;

  if (pageType === 'product') {
    if (!extractedData.sku || !extractedData.name) {
      throw new Error('Missing required fields: sku or name');
    }

    // Ensure arrays exist
    extractedData.images = extractedData.images || [];
    extractedData.videos = extractedData.videos || [];
    extractedData.metadata = extractedData.metadata || {};
  } else if (pageType === 'catalog') {
    if (!Array.isArray(extractedData)) {
      throw new Error('Catalog extraction must return an array');
    }
  }

  return {
    success: true,
    data: extractedData,
    url: $('Load AI Prompts').item.json.url,
    pageType: pageType,
    extractedAt: new Date().toISOString(),
    cost: 0.002 // Approximate cost per request
  };

} catch (error) {
  return {
    success: false,
    error: error.message,
    url: $('Load AI Prompts').item.json.url,
    rawResponse: response
  };
}
